/* Count basic blocks per function - a minimal GCC GIMPLE optimization pass.
   This pass demonstrates the structure of a GCC GIMPLE pass by counting
   and reporting the number of basic blocks in each function.

   Copyright (C) 2026 Free Software Foundation, Inc.

This file is part of GCC.

GCC is free software; you can redistribute it and/or modify it
under the terms of the GNU General Public License as published by the
Free Software Foundation; either version 3, or (at your option) any
later version.

GCC is distributed in the hope that it will be useful, but WITHOUT
ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or
FITNESS FOR A PARTICULAR PURPOSE.  See the GNU General Public License
for more details.

You should have received a copy of the GNU General Public License
along with GCC; see the file COPYING3.  If not see
<http://www.gnu.org/licenses/>.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "cfghooks.h"
#include "tree-pass.h"
#include "tree-cfg.h"

namespace {

/* Pass data structure defining pass metadata.  */
const pass_data pass_data_count_basic_blocks =
{
  GIMPLE_PASS,                 /* type */
  "count_basic_blocks",        /* name */
  OPTGROUP_NONE,               /* optinfo_flags */
  TV_NONE,                     /* tv_id */
  ( PROP_cfg | PROP_ssa ),     /* properties_required */
  0,                           /* properties_provided */
  0,                           /* properties_destroyed */
  0,                           /* todo_flags_start */
  0,                           /* todo_flags_finish */
};

/* The pass class inheriting from gimple_opt_pass.  */
class pass_count_basic_blocks : public gimple_opt_pass
{
public:
  pass_count_basic_blocks (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_basic_blocks, ctxt)
  {
  }

  /* opt_pass methods: */

  /* Implement the gate method - determines if this pass should run.
     Returns true to enable the pass.  */
  bool gate (function *) final override
  {
    return true;
  }

  /* Implement the execute method - the main pass logic.
     Returns TODO flags indicating any subsequent actions needed.  */
  unsigned int execute (function *fun) final override;

}; // class pass_count_basic_blocks

/* Implementation of the execute method.
   This method iterates through all basic blocks in the function,
   counts them, and outputs debug information.  */
unsigned int
pass_count_basic_blocks::execute (function *fun)
{
  basic_block bb;
  unsigned int count = 0;

  /* Count the basic blocks in the function using FOR_EACH_BB_FN macro.  */
  FOR_EACH_BB_FN (bb, fun)
    {
      count++;
    }

  /* Output debug information using dump_file for tracing.  */
  if (dump_file)
    {
      fprintf (dump_file, "Function %s has %u basic blocks\n",
               function_name (fun), count);
    }

  /* Return 0 to indicate no TODO items are needed after this pass.  */
  return 0;
}

} // anon namespace

/* Factory function to create an instance of the pass.
   This function is called by the GCC pass manager to instantiate
   the pass for a given compilation context.  */
gimple_opt_pass *
make_pass_count_basic_blocks (gcc::context *ctxt)
{
  return new pass_count_basic_blocks (ctxt);
}

